marks = 85

if marks >= 90:
    print("Grade: A")
elif marks >= 80:
    # This runs if marks < 90 AND marks >= 80
    print("Grade: B")
elif marks >= 70:
    print("Grade: C")
else:
    # This is the catch-all if none of the above are True
    print("Grade: F")

# Prints 0, 1, 2, 3, 4
for i in range(5):
    print(i)

# Prints 2, 4, 6, 8 (Starts at 2, goes up to 9, steps by 2)
for i in range(2, 10, 2):
    print(i)
